mapper.select:
SELECT l.id, l.automation_type, l.event_key, l.trigger_type, l.trigger_reason,
       l.user_id, l.target_id, l.success, l.detail, l.event_time, l.created_by,
       p.name AS user_name
FROM twin_automation_log l
LEFT JOIN aro_personnel p ON l.user_id = p.user_id
WHERE l.user_id = #{userId}
  AND l.event_time >= #{fromTime}
  AND l.event_time <= #{toTime}

      AND NOT (l.automation_type = 'SCHEDULER' AND l.event_key = 'ARO_PENETRATION_POLL')

ORDER BY l.event_time DESC, l.id DESC
LIMIT #{limit}
